export const SPONSOR_EMAIL = "leonelngoya@gmail.com"

/** Build a sponsorship mailto link, optionally pre-filled with a tier. */
export function sponsorMailto(tier?: string) {
  return `mailto:${SPONSOR_EMAIL}?subject=${encodeURIComponent(
    tier ? `Sponsoring threecn — ${tier}` : "Sponsoring threecn"
  )}&body=${encodeURIComponent(
    "Hi Leonel,\n\nI'd love to sponsor threecn. A few details:\n\n- Name / company:\n- Website:\n- Tier of interest:\n\nThanks!"
  )}`
}

export const SPONSOR_HREF = sponsorMailto()

