export type Sponsor = {
  name: string
  url: string
  logo: React.ComponentType<{ className?: string }>
}

export type SponsorTier = {
  key: string
  label: string
  sponsors: Sponsor[]
  /** Open placeholder slots rendered as "your logo here" tiles. */
  spots: number
}

